    border: 1px solid #dee2e6;
    color: #212529;
    min-width: 2.2rem;
    text-align: center;
}

.btn-page:hover:not(:disabled) {
    background: #e9ecef;
}

.btn-page.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

/* States */
.loading-indicator,
.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: #6c757d;
}

.alert-danger {
    background: #f8d7da;
    border: 1px solid #f5c2c7;
    color: #842029;
    padding: 1rem;
    border-radius: 8px;
    margin-bottom: 1rem;
}

.text-muted {
    color: #6c757d;
    font-size: 0.85rem;
}
"}

toolArgs.file_text:
namespace sv_a7eeebc2b71349a0b109cb2463c53a28.Models;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

using sv_a7eeebc2b71349a0b109cb2463c53a28.Models;

namespace sv_a7eeebc2b71349a0b109cb2463c53a28.Services;

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_a7eeebc2b71349a0b109cb2463c53a28.Models
@using sv_a7eeebc2b71349a0b109cb2463c53a28.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

<div class="catalog-layout">
    <!-- Left Sidebar: Filters -->
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Categories</h4>
            @if (categories is not null)
            {
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
            else
            {
                <p class="text-muted">Loading categories…</p>
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <label>
                Min Price
                <input type="number" min="0" step="0.01" @bind="minPrice" class="filter-input" />
            </label>
            <label>
                Max Price
                <input type="number" min="0" step="0.01" @bind="maxPrice" class="filter-input" />
            </label>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <section class="catalog-main">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-link" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (isLoading)
        {
            <div class="loading-indicator">
                <p>Loading products…</p>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="empty-state">
                <p>No products found matching your criteria.</p>
                <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
            </div>
        }
        else
        {
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="toolbar-sort">
                    <label for="sortSelect">Sort by:</label>
                    <select id="sortSelect" @bind="sortBy" @bind:after="OnSortChanged" class="form-select">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <div class="toolbar-info">
                    Showing @(((result.Page - 1) * result.PageSize) + 1)–@(Math.Min(result.Page * result.PageSize, result.TotalCount)) of @result.TotalCount products
                </div>
            </div>

            <!-- Product Grid -->
            <div class="product-grid">
                @foreach (var product in result.Items)
                {
                    <div class="product-card" @onclick="() => OnProductSelected(product)" tabindex="0">
                        <div class="product-image" title="@product.Name">
                            @product.Name
                        </div>
                        <div class="product-info">
                            <h5 class="product-name">@product.Name</h5>
                            <p class="product-price">@product.Price.ToString("C")</p>
                            <p class="product-rating">@GetStarRating(product.Rating)</p>
                            @if (!product.InStock)
                            {
                                <span class="badge-out-of-stock">Out of Stock</span>
                            }
                            <button class="btn btn-cart"
                                    disabled="@(!product.InStock)"
                                    @onclick="() => AddToCart(product)"
                                    @onclick:stopPropagation="true">
                                Add to Cart
                            </button>
                        </div>
                    </div>
                }
            </div>

            <!-- Pagination -->
            @if (totalPages > 1)
            {
                <nav class="pagination-controls">
                    <button class="btn btn-page"
                            disabled="@(currentPage <= 1)"
                            @onclick="() => GoToPage(currentPage - 1)">
                        Previous
                    </button>

                    @for (int i = 1; i <= totalPages; i++)
                    {
                        var pageNum = i;
                        <button class="btn btn-page @(pageNum == currentPage ? "active" : "")"
                                @onclick="() => GoToPage(pageNum)">
                            @pageNum
                        </button>
                    }

                    <button class="btn btn-page"
                            disabled="@(currentPage >= totalPages)"
                            @onclick="() => GoToPage(currentPage + 1)">
                        Next
                    </button>
                </nav>
            }
        }
    </section>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductClicked { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int totalPages => result is null || result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialData();
    }

    private async Task LoadInitialData()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProducts();
            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load catalog: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await SearchProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await SearchProducts();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await SearchProducts();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await SearchProducts();
    }

    private async Task RetryLoad()
    {
        await LoadInitialData();
    }

    private async Task OnProductSelected(Product product)
    {
        if (OnProductClicked.HasDelegate)
        {
            await OnProductClicked.InvokeAsync(product);
        }
    }

    private void AddToCart(Product product)
    {
        // Cart functionality to be implemented
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

